"""Extract a condensed view of an entire session transcript.

Reads Claude Code JSONL transcripts (and best-effort handles other agents)
and prints a structured plaintext dump that the bring-context skill turns
into a 6-section compaction summary.
"""

import json
import sys
from pathlib import Path

NOISE_PREFIXES = (
    "Base directory for this skill:",
    "<system-reminder>",
    "<command-name>",
    "<command-message>",
    "<command-args>",
    "<local-command-stdout>",
    "<local-command-stderr>",
    "<local-command-caveat>",
)

FILE_TOUCHING_TOOLS = {"Edit", "Write", "MultiEdit", "NotebookEdit"}


def trunc(s, n=2000):
    if not isinstance(s, str):
        s = str(s)
    return s if len(s) <= n else s[:n] + "...[truncated]"


def is_noise(text):
    if not text:
        return False
    stripped = text.lstrip()
    return any(stripped.startswith(p) for p in NOISE_PREFIXES)


def extract_text(content):
    """Render assistant/user content (string or list-of-blocks) as plain text."""
    if isinstance(content, str):
        return content
    if not isinstance(content, list):
        return ""
    parts = []
    for block in content:
        if not isinstance(block, dict):
            continue
        btype = block.get("type")
        if btype == "text":
            parts.append(block.get("text", ""))
        elif btype == "tool_use":
            name = block.get("name", "tool")
            try:
                inp = json.dumps(block.get("input", {}), ensure_ascii=False)
            except (TypeError, ValueError):
                inp = str(block.get("input", ""))
            parts.append(f"[tool_use:{name}] {trunc(inp, 500)}")
        elif btype == "tool_result":
            res = extract_text(block.get("content", ""))
            parts.append(f"[tool_result] {trunc(res, 500)}")
    return "\n".join(parts)


def main():
    if len(sys.argv) != 2:
        print("usage: extract.py <transcript_path>", file=sys.stderr)
        sys.exit(2)

    path = Path(sys.argv[1])
    if not path.exists():
        print(f"ERROR: transcript not found at {path}", file=sys.stderr)
        sys.exit(2)

    user_prompts = []
    assistant_texts = []
    tool_calls = []
    files_modified = set()

    with path.open("r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except json.JSONDecodeError:
                continue

            msg = obj.get("message") or obj
            role = msg.get("role") or obj.get("type")
            content = msg.get("content")

            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get("type") == "tool_use":
                        if block.get("name") in FILE_TOUCHING_TOOLS:
                            fp = block.get("input", {}).get("file_path")
                            if fp:
                                files_modified.add(fp)

            text = extract_text(content)
            if not text or is_noise(text):
                continue

            if role == "user":
                user_prompts.append(text)
            elif role == "assistant":
                for piece in text.split("\n"):
                    if piece.startswith("[tool_use:"):
                        tool_calls.append(piece)
                    elif piece.strip():
                        assistant_texts.append(piece)

    print("=== User prompts ===")
    if not user_prompts:
        print("(none extracted)")
    for i, p in enumerate(user_prompts, 1):
        print(f"[{i}] {trunc(p, 1500)}")
        print()

    print("=== Files modified ===")
    if files_modified:
        for fp in sorted(files_modified):
            print(f"  {fp}")
    else:
        print("  (none)")
    print()

    print("=== Tool activity (last 30) ===")
    if tool_calls:
        for tc in tool_calls[-30:]:
            print(trunc(tc, 300))
    else:
        print("(none)")
    print()

    print("=== Assistant text (last 12 chunks) ===")
    if assistant_texts:
        for at in assistant_texts[-12:]:
            print(trunc(at, 1500))
            print()
    else:
        print("(none)")


if __name__ == "__main__":
    main()

