            role = msg.get("role") or obj.get("type")
            content = msg.get("content")

            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get("type") == "tool_use":
                        if block.get("name") in FILE_TOUCHING_TOOLS:
                            fp = block.get("input", {}).get("file_path")
                            if fp:
                                files_modified.add(fp)

            text = extract_text(content)
            if not text or is_noise(text):
                continue

            if role == "user":
                user_prompts.append(text)
            elif role == "assistant":
                for piece in text.split("\n"):
                    if piece.startswith("[tool_use:"):
                        tool_calls.append(piece)
                    elif piece.strip():
                        assistant_texts.append(piece)

    print("=== User prompts ===")
    if not user_prompts:
        print("(none extracted)")
    for i, p in enumerate(user_prompts, 1):
        print(f"[{i}] {trunc(p, 1500)}")
        print()

    print("=== Files modified ===")
    if files_modified:
        for fp in sorted(files_modified):
            print(f"  {fp}")
    else:
        print("  (none)")
    print()

    print("=== Tool activity (last 30) ===")
    if tool_calls:
        for tc in tool_calls[-30:]:
            print(trunc(tc, 300))
    else:
        print("(none)")
    print()

    print("=== Assistant text (last 12 chunks) ===")
    if assistant_texts:
        for at in assistant_texts[-12:]:
            print(trunc(at, 1500))
            print()
    else:
        print("(none)")


if __name__ == "__main__":
